package com.taskflow.security;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.*;

class JwtUtilTest {

    private JwtUtil jwtUtil;

    // Use a secret long enough for HMAC-SHA256 (>=32 bytes)
    private static final String TEST_SECRET = "test-jwt-secret-key-that-is-long-enough-for-hmac-sha256";
    private static final long TEST_EXPIRATION = 86400000L; // 24 hours

    @BeforeEach
    void setUp() {
        jwtUtil = new JwtUtil(TEST_SECRET, TEST_EXPIRATION);
    }

    // === Red/Green: Acceptance Criteria ===

    @Test
    void should_generate_token_when_given_valid_userId() {
        Long userId = 1L;
        String token = jwtUtil.generateToken(userId);

        assertNotNull(token);
        assertFalse(token.isEmpty());
    }

    @Test
    void should_return_userId_when_given_valid_token() {
        Long userId = 42L;
        String token = jwtUtil.generateToken(userId);

        Long extractedUserId = jwtUtil.getUserIdFromToken(token);

        assertEquals(userId, extractedUserId);
    }

    @Test
    void should_return_true_when_validating_valid_token() {
        Long userId = 1L;
        String token = jwtUtil.generateToken(userId);

        boolean isValid = jwtUtil.validateToken(token);

        assertTrue(isValid);
    }

    // === Contract Tests ===

    @Test
    void should_produce_three_part_jwt_format() {
        // JWT format: header.payload.signature
        String token = jwtUtil.generateToken(1L);

        String[] parts = token.split("\\.");
        assertEquals(3, parts.length, "JWT should have 3 parts separated by dots");
    }

    @Test
    void should_contain_userId_claim_in_token() {
        Long userId = 99L;
        String token = jwtUtil.generateToken(userId);

        // Round-trip: the userId we put in must come back out
        Long extracted = jwtUtil.getUserIdFromToken(token);
        assertEquals(userId, extracted);
    }

    @Test
    void should_generate_different_tokens_for_different_users() {
        String token1 = jwtUtil.generateToken(1L);
        String token2 = jwtUtil.generateToken(2L);

        assertNotEquals(token1, token2);
    }

    // === Boundary Tests ===

    @Test
    void should_return_false_when_validating_malformed_token() {
        boolean isValid = jwtUtil.validateToken("not-a-valid-jwt");

        assertFalse(isValid);
    }

    @Test
    void should_return_false_when_validating_empty_token() {
        boolean isValid = jwtUtil.validateToken("");

        assertFalse(isValid);
    }

    @Test
    void should_return_false_when_validating_null_token() {
        boolean isValid = jwtUtil.validateToken(null);

        assertFalse(isValid);
    }

    @Test
    void should_return_false_when_token_signed_with_different_secret() {
        // Generate token with a different secret
        JwtUtil otherJwtUtil = new JwtUtil(
            "different-secret-key-that-is-also-long-enough-for-hmac",
            TEST_EXPIRATION
        );
        String token = otherJwtUtil.generateToken(1L);

        // Validate with our jwtUtil (different secret) should fail
        boolean isValid = jwtUtil.validateToken(token);

        assertFalse(isValid);
    }

    @Test
    void should_return_false_when_token_is_expired() {
        // Create a JwtUtil with 0ms expiration (immediately expired)
        JwtUtil expiredJwtUtil = new JwtUtil(TEST_SECRET, 0L);
        String token = expiredJwtUtil.generateToken(1L);

        // Token should be expired immediately (or within ms)
        boolean isValid = jwtUtil.validateToken(token);

        assertFalse(isValid);
    }

    // === Error Cases ===

    @Test
    void should_throw_when_extracting_userId_from_invalid_token() {
        assertThrows(Exception.class, () -> {
            jwtUtil.getUserIdFromToken("invalid-token");
        });
    }

    @Test
    void should_throw_when_extracting_userId_from_expired_token() {
        JwtUtil expiredJwtUtil = new JwtUtil(TEST_SECRET, 0L);
        String token = expiredJwtUtil.generateToken(1L);

        assertThrows(Exception.class, () -> {
            jwtUtil.getUserIdFromToken(token);
        });
    }
}

