package com.taskflow.dto;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.*;

class UserResponseTest {

    @Test
    void should_create_user_response_with_all_fields() {
        UserResponse userResponse = new UserResponse(1L, "testuser", "Test User");

        assertEquals(1L, userResponse.id());
        assertEquals("testuser", userResponse.username());
        assertEquals("Test User", userResponse.displayName());
    }

    @Test
    void should_have_correct_field_types() {
        UserResponse userResponse = new UserResponse(99L, "admin", "Admin User");

        assertInstanceOf(Long.class, userResponse.id());
        assertInstanceOf(String.class, userResponse.username());
        assertInstanceOf(String.class, userResponse.displayName());
    }
}

